Rule.Source:

import sailpoint.object.*;
import java.util.*;

String ruleName = "ServiceAccountExclusion";

// --- Configuration ---
List servicePatterns = Arrays.asList(new String[]{"svc_", "SVC-", "system_", "admin_"});
String typeAttribute = "identityType";
List serviceTypes = Arrays.asList(new String[]{"service", "system", "rpa"});
boolean excludeInactive = true;

// --- Rule Logic ---
String identityName = entity.getIdentity(context).getName();
Identity identity = entity.getIdentity(context);
log.info("[" + ruleName + "] Evaluating: " + identityName);

// Check name patterns
Iterator patternIter = servicePatterns.iterator();
while (patternIter.hasNext()) {
    String pattern = (String) patternIter.next();
    if (identityName.startsWith(pattern)) {
        log.info("[" + ruleName + "] Excluding " + identityName + " (matches pattern: " + pattern + ")");
        return "Service account: name matches pattern " + pattern;
    }
}

// Check identity type
String identityType = identity.getStringAttribute(typeAttribute);
if (identityType != null && serviceTypes.contains(identityType.toLowerCase())) {
    log.info("[" + ruleName + "] Excluding " + identityName + " (identity type: " + identityType + ")");
    return "Service account: identity type is " + identityType;
}

// Check inactive
if (excludeInactive && identity.isInactive()) {
    log.info("[" + ruleName + "] Excluding " + identityName + " (inactive)");
    return "Identity is inactive";
}

log.debug("[" + ruleName + "] Including " + identityName);
return null;
